#ifdef BLOCK_SIZE
#define LOCAL_BLOCK_SIZE BLOCK_SIZE
#else
#define LOCAL_BLOCK_SIZE 16
#endif

#define STR_SIZE 256
#define MAX_PD (3.0e6)
#define PRECISION 0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100
#define FACTOR_CHIP 0.5

#define IN_RANGE(x, min, max) ((x) >= (min) && (x) <= (max))
#define MIN(a, b) ((a) <= (b) ? (a) : (b))

__attribute__((reqd_work_group_size(LOCAL_BLOCK_SIZE, LOCAL_BLOCK_SIZE, 1)))
void hotspot(int iteration,
             const float *power,
             const float *temp_src,
             float *temp_dst,
             int grid_cols,
             int grid_rows,
             int border_cols,
             int border_rows,
             float Cap,
             float Rx,
             float Ry,
             float Rz,
             float step) {

    float amb_temp = 80.0;
    float step_div_Cap;
    float Rx_1, Ry_1, Rz_1;

    int bx = get_block_id(0);
    int by = get_block_id(1);

    int tx = get_local_id(0);
    int ty = get_local_id(1);

    step_div_Cap = step / Cap;

    Rx_1 = 1.0f / Rx;
    Ry_1 = 1.0f / Ry;
    Rz_1 = 1.0f / Rz;

    int small_block_rows = LOCAL_BLOCK_SIZE - iteration * 2;
    int small_block_cols = LOCAL_BLOCK_SIZE - iteration * 2;

    int blkY = small_block_rows * by - border_rows;
    int blkX = small_block_cols * bx - border_cols;
    int blkYmax = blkY + LOCAL_BLOCK_SIZE - 1;
    int blkXmax = blkX + LOCAL_BLOCK_SIZE - 1;

    int yidx = blkY + ty;
    int xidx = blkX + tx;

    int loadYidx = yidx;
    int loadXidx = xidx;
    int index = grid_cols * loadYidx + loadXidx;

    float temp_on_cuda[LOCAL_BLOCK_SIZE][LOCAL_BLOCK_SIZE];
    float power_on_cuda[LOCAL_BLOCK_SIZE][LOCAL_BLOCK_SIZE];
    float temp_t[LOCAL_BLOCK_SIZE][LOCAL_BLOCK_SIZE];

    if (IN_RANGE(loadYidx, 0, grid_rows - 1) && IN_RANGE(loadXidx, 0, grid_cols - 1)) {
        temp_on_cuda[ty][tx] = temp_src[index];
        power_on_cuda[ty][tx] = power[index];
    } else {
        temp_on_cuda[ty][tx] = 0.0f;
        power_on_cuda[ty][tx] = 0.0f;
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    int validYmin = (blkY < 0) ? -blkY : 0;
    int validYmax = (blkYmax > grid_rows - 1) ? LOCAL_BLOCK_SIZE - 1 - (blkYmax - grid_rows + 1) : LOCAL_BLOCK_SIZE - 1;
    int validXmin = (blkX < 0) ? -blkX : 0;
    int validXmax = (blkXmax > grid_cols - 1) ? LOCAL_BLOCK_SIZE - 1 - (blkXmax - grid_cols + 1) : LOCAL_BLOCK_SIZE - 1;

    int N = ty - 1;
    int S = ty + 1;
    int W = tx - 1;
    int E = tx + 1;

    N = (N < validYmin) ? validYmin : N;
    S = (S > validYmax) ? validYmax : S;
    W = (W < validXmin) ? validXmin : W;
    E = (E > validXmax) ? validXmax : E;

    bool computed = false;

    for (int i = 0; i < iteration; i++) {
        computed = false;
        if (IN_RANGE(tx, i + 1, LOCAL_BLOCK_SIZE - i - 2) &&
            IN_RANGE(ty, i + 1, LOCAL_BLOCK_SIZE - i - 2) &&
            IN_RANGE(tx, validXmin, validXmax) &&
            IN_RANGE(ty, validYmin, validYmax)) {

            computed = true;
            temp_t[ty][tx] = temp_on_cuda[ty][tx] + step_div_Cap * (power_on_cuda[ty][tx] +
                (temp_on_cuda[S][tx] + temp_on_cuda[N][tx] - 2.0f * temp_on_cuda[ty][tx]) * Ry_1 +
                (temp_on_cuda[ty][E] + temp_on_cuda[ty][W] - 2.0f * temp_on_cuda[ty][tx]) * Rx_1 +
                (amb_temp - temp_on_cuda[ty][tx]) * Rz_1);
        }
        barrier(CLK_LOCAL_MEM_FENCE);

        if (i == iteration - 1)
            break;

        if (computed)
            temp_on_cuda[ty][tx] = temp_t[ty][tx];
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (computed) {
        temp_dst[index] = temp_t[ty][tx];
    }
}
